import{_ as t,o as a,c as d,a2 as o}from"./chunks/framework.DeNJmwJc.js";const m=JSON.parse('{"title":"Chapter 7 — Understanding Modes","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/07-understanding-modes.md","filePath":"chapters/07-understanding-modes.md"}'),n={name:"chapters/07-understanding-modes.md"};function s(i,e,r,l,c,h){return a(),d("div",null,[...e[0]||(e[0]=[o(`<h1 id="chapter-7-—-understanding-modes" tabindex="-1">Chapter 7 — Understanding Modes <a class="header-anchor" href="#chapter-7-—-understanding-modes" aria-label="Permalink to &quot;Chapter 7 — Understanding Modes&quot;">​</a></h1><blockquote><p><em>&quot;Modes are not a limitation—they are a superpower.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐ Beginner <strong>Estimated Reading Time:</strong> 20–25 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Most text editors have one mode:</p><blockquote><p>You type, text appears.</p></blockquote><p>Vim has <strong>multiple modes</strong>.</p><p>This sounds complicated, but actually it&#39;s what makes Vim powerful.</p><p>Think of it this way:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Normal mode  =  Steering wheel (driving, navigating)</span></span>
<span class="line"><span>Insert mode  =  Accelerator (moving forward)</span></span>
<span class="line"><span>Visual mode  =  Highlighting (selecting)</span></span>
<span class="line"><span>Command mode =  Controls (signals, wipers)</span></span></code></pre></div><p>Each mode has a specific job.</p><hr><h1 id="the-four-main-modes" tabindex="-1">The Four Main Modes <a class="header-anchor" href="#the-four-main-modes" aria-label="Permalink to &quot;The Four Main Modes&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th><th>Enter</th><th>Exit</th></tr></thead><tbody><tr><td>Normal</td><td>Navigation, editing commands</td><td>Escape, Ctrl+[</td><td>N/A (default)</td></tr><tr><td>Insert</td><td>Typing text</td><td>i, a, o, etc.</td><td>Escape</td></tr><tr><td>Visual</td><td>Selecting text</td><td>v, V, Ctrl+v</td><td>Escape</td></tr><tr><td>Command</td><td>Running commands</td><td>:</td><td>Enter, Escape</td></tr></tbody></table><hr><h1 id="normal-mode" tabindex="-1">Normal Mode <a class="header-anchor" href="#normal-mode" aria-label="Permalink to &quot;Normal Mode&quot;">​</a></h1><p>This is Vim&#39;s <strong>default mode</strong>.</p><p>You start in normal mode when you open Vim.</p><h2 id="what-normal-mode-is-for" tabindex="-1">What Normal Mode Is For <a class="header-anchor" href="#what-normal-mode-is-for" aria-label="Permalink to &quot;What Normal Mode Is For&quot;">​</a></h2><ul><li>Moving around the file</li><li>Deleting, copying, pasting</li><li>Searching</li><li>Undoing and redoing</li><li>Running commands</li><li>Everything except typing text</li></ul><h2 id="key-concept" tabindex="-1">Key Concept <a class="header-anchor" href="#key-concept" aria-label="Permalink to &quot;Key Concept&quot;">​</a></h2><p>In normal mode, <strong>keys are commands, not text</strong>.</p><table tabindex="0"><thead><tr><th>Key</th><th>Command</th></tr></thead><tbody><tr><td><code>j</code></td><td>Move down</td></tr><tr><td><code>k</code></td><td>Move up</td></tr><tr><td><code>dd</code></td><td>Delete a line</td></tr><tr><td><code>yy</code></td><td>Copy (yank) a line</td></tr><tr><td><code>u</code></td><td>Undo</td></tr></tbody></table><p>Return to normal mode from any other mode by pressing <strong>Escape</strong>.</p><hr><h1 id="insert-mode" tabindex="-1">Insert Mode <a class="header-anchor" href="#insert-mode" aria-label="Permalink to &quot;Insert Mode&quot;">​</a></h1><p>Insert mode is where you <strong>type text</strong>.</p><h2 id="entering-insert-mode" tabindex="-1">Entering Insert Mode <a class="header-anchor" href="#entering-insert-mode" aria-label="Permalink to &quot;Entering Insert Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>i</code></td><td>Insert before cursor</td></tr><tr><td><code>a</code></td><td>Append after cursor</td></tr><tr><td><code>I</code></td><td>Insert at beginning of line</td></tr><tr><td><code>A</code></td><td>Append at end of line</td></tr><tr><td><code>o</code></td><td>Open a new line below and insert</td></tr><tr><td><code>O</code></td><td>Open a new line above and insert</td></tr><tr><td><code>s</code></td><td>Delete character and insert</td></tr><tr><td><code>S</code></td><td>Delete line and insert</td></tr><tr><td><code>C</code></td><td>Delete from cursor to end of line, insert</td></tr></tbody></table><h2 id="while-in-insert-mode" tabindex="-1">While in Insert Mode <a class="header-anchor" href="#while-in-insert-mode" aria-label="Permalink to &quot;While in Insert Mode&quot;">​</a></h2><ul><li>Keys type text normally.</li><li>Arrow keys move the cursor (but using <code>h</code>/<code>j</code>/<code>k</code>/<code>l</code> requires normal mode).</li><li>Backspace deletes previous characters.</li></ul><h2 id="exiting-insert-mode" tabindex="-1">Exiting Insert Mode <a class="header-anchor" href="#exiting-insert-mode" aria-label="Permalink to &quot;Exiting Insert Mode&quot;">​</a></h2><p>Press <strong>Escape</strong>.</p><p>Or use <code>Ctrl+C</code> or <code>Ctrl+[</code> .</p><hr><h1 id="visual-mode" tabindex="-1">Visual Mode <a class="header-anchor" href="#visual-mode" aria-label="Permalink to &quot;Visual Mode&quot;">​</a></h1><p>Visual mode is for <strong>selecting text</strong>.</p><h2 id="types-of-visual-mode" tabindex="-1">Types of Visual Mode <a class="header-anchor" href="#types-of-visual-mode" aria-label="Permalink to &quot;Types of Visual Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Selection Type</th></tr></thead><tbody><tr><td><code>v</code></td><td>Character-wise select</td></tr><tr><td><code>V</code></td><td>Line-wise select</td></tr><tr><td><code>Ctrl+v</code></td><td>Block (column) select</td></tr></tbody></table><h2 id="character-wise-visual-mode-v" tabindex="-1">Character-Wise Visual Mode (<code>v</code>) <a class="header-anchor" href="#character-wise-visual-mode-v" aria-label="Permalink to &quot;Character-Wise Visual Mode (\`v\`)&quot;">​</a></h2><p>Press <code>v</code> and move the cursor.</p><p>Characters are highlighted as you move.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>
<span class="line"><span>^^^^^^^     ← highlighted</span></span></code></pre></div><h2 id="line-wise-visual-mode-v" tabindex="-1">Line-Wise Visual Mode (<code>V</code>) <a class="header-anchor" href="#line-wise-visual-mode-v" aria-label="Permalink to &quot;Line-Wise Visual Mode (\`V\`)&quot;">​</a></h2><p>Press <code>V</code> and move up/down.</p><p>Entire lines are highlighted.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Line one       ← highlighted</span></span>
<span class="line"><span>Line two       ← highlighted</span></span>
<span class="line"><span>Line three</span></span></code></pre></div><h2 id="block-visual-mode-ctrl-v" tabindex="-1">Block Visual Mode (<code>Ctrl+v</code>) <a class="header-anchor" href="#block-visual-mode-ctrl-v" aria-label="Permalink to &quot;Block Visual Mode (\`Ctrl+v\`)&quot;">​</a></h2><p>Press <code>Ctrl+v</code> and move in any direction.</p><p>Selects a rectangular block of text.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Col1    Col2    Col3</span></span>
<span class="line"><span>^^^^    ^^^^</span></span>
<span class="line"><span>^^^^    ^^^^</span></span>
<span class="line"><span>only these columns selected</span></span></code></pre></div><h2 id="what-to-do-with-selections" tabindex="-1">What to Do With Selections <a class="header-anchor" href="#what-to-do-with-selections" aria-label="Permalink to &quot;What to Do With Selections&quot;">​</a></h2><p>Once text is selected:</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>d</code></td><td>Delete</td></tr><tr><td><code>y</code></td><td>Yank (copy)</td></tr><tr><td><code>c</code></td><td>Change (delete + insert)</td></tr><tr><td><code>&gt;</code></td><td>Indent right</td></tr><tr><td><code>&lt;</code></td><td>Indent left</td></tr><tr><td><code>~</code></td><td>Toggle case</td></tr><tr><td><code>u</code></td><td>Lowercase</td></tr><tr><td><code>U</code></td><td>Uppercase</td></tr></tbody></table><p>Exit visual mode with <strong>Escape</strong>.</p><hr><h1 id="command-mode" tabindex="-1">Command Mode <a class="header-anchor" href="#command-mode" aria-label="Permalink to &quot;Command Mode&quot;">​</a></h1><p>Command mode is for running <strong>ex-commands</strong> (inherited from the <code>ex</code> editor).</p><h2 id="entering-command-mode" tabindex="-1">Entering Command Mode <a class="header-anchor" href="#entering-command-mode" aria-label="Permalink to &quot;Entering Command Mode&quot;">​</a></h2><p>From normal mode, press <code>:</code>.</p><p>The cursor jumps to the bottom of the screen.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:_</span></span></code></pre></div><h2 id="common-commands" tabindex="-1">Common Commands <a class="header-anchor" href="#common-commands" aria-label="Permalink to &quot;Common Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:w</code></td><td>Save file</td></tr><tr><td><code>:q</code></td><td>Quit</td></tr><tr><td><code>:wq</code></td><td>Save and quit</td></tr><tr><td><code>:q!</code></td><td>Quit without saving</td></tr><tr><td><code>:e file</code></td><td>Open a file</td></tr><tr><td><code>:help</code></td><td>Open help</td></tr><tr><td><code>:set nu</code></td><td>Show line numbers</td></tr><tr><td><code>:!cmd</code></td><td>Run shell command</td></tr></tbody></table><p>Press <strong>Enter</strong> to execute the command.</p><p>Press <strong>Escape</strong> to cancel.</p><hr><h1 id="additional-modes" tabindex="-1">Additional Modes <a class="header-anchor" href="#additional-modes" aria-label="Permalink to &quot;Additional Modes&quot;">​</a></h1><h2 id="replace-mode" tabindex="-1">Replace Mode <a class="header-anchor" href="#replace-mode" aria-label="Permalink to &quot;Replace Mode&quot;">​</a></h2><p>Enter with <code>R</code> (capital R).</p><p>Overwrites existing characters instead of inserting.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>
<span class="line"><span>R</span></span>
<span class="line"><span>Rello World    ← H replaced with R</span></span></code></pre></div><h2 id="terminal-mode-neovim-only" tabindex="-1">Terminal Mode (Neovim Only) <a class="header-anchor" href="#terminal-mode-neovim-only" aria-label="Permalink to &quot;Terminal Mode (Neovim Only)&quot;">​</a></h2><p>Enter with <code>:terminal</code> or <code>:term</code>.</p><p>Works like a terminal inside Neovim.</p><p>Exit with <code>Ctrl+\\ Ctrl+n</code> to return to normal mode.</p><hr><h1 id="mode-switching-diagram" tabindex="-1">Mode Switching Diagram <a class="header-anchor" href="#mode-switching-diagram" aria-label="Permalink to &quot;Mode Switching Diagram&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                 +--------------+</span></span>
<span class="line"><span>                 |   NORMAL     | ← Default mode</span></span>
<span class="line"><span>                 +--------------+</span></span>
<span class="line"><span>                  ↕ ↑        ↓ ↕</span></span>
<span class="line"><span>            Esc   │ │ i,a,o  │ │     v,V,Ctrl+v</span></span>
<span class="line"><span>                  │ │   s,S  │ │</span></span>
<span class="line"><span>             +--------+   +--------+</span></span>
<span class="line"><span>             | INSERT |   | VISUAL |</span></span>
<span class="line"><span>             +--------+   +--------+</span></span>
<span class="line"><span>                  │            │</span></span>
<span class="line"><span>             +---------+  +---------+</span></span>
<span class="line"><span>             | REPLACE |  | COMMAND | ← : enters this</span></span>
<span class="line"><span>             +---------+  +---------+</span></span></code></pre></div><hr><h1 id="common-mistake-staying-in-insert-mode" tabindex="-1">Common Mistake: Staying in Insert Mode <a class="header-anchor" href="#common-mistake-staying-in-insert-mode" aria-label="Permalink to &quot;Common Mistake: Staying in Insert Mode&quot;">​</a></h1><p>Beginners often stay in insert mode and use arrow keys.</p><p>This defeats the purpose of Vim.</p><p><strong>Pattern to develop:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Normal → Insert → Normal → Insert → Normal</span></span></code></pre></div><p>Enter insert mode only to type, then immediately return to normal mode.</p><hr><h1 id="visual-indicators" tabindex="-1">Visual Indicators <a class="header-anchor" href="#visual-indicators" aria-label="Permalink to &quot;Visual Indicators&quot;">​</a></h1><p>Vim shows your current mode in the bottom left:</p><table tabindex="0"><thead><tr><th>Indicator</th><th>Mode</th></tr></thead><tbody><tr><td>(nothing)</td><td>Normal</td></tr><tr><td><code>-- INSERT --</code></td><td>Insert</td></tr><tr><td><code>-- VISUAL --</code></td><td>Visual</td></tr><tr><td><code>-- V-BLOCK --</code></td><td>Visual Block</td></tr><tr><td><code>-- REPLACE --</code></td><td>Replace</td></tr><tr><td><code>:</code></td><td>Command line about to be entered</td></tr></tbody></table><p>Watch this indicator—it tells you what mode you&#39;re in.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th><th>Enter</th></tr></thead><tbody><tr><td>Normal</td><td>Navigation, commands</td><td>Escape</td></tr><tr><td>Insert</td><td>Typing text</td><td><code>i</code>, <code>a</code>, <code>o</code></td></tr><tr><td>Visual</td><td>Selecting text</td><td><code>v</code>, <code>V</code>, <code>Ctrl+v</code></td></tr><tr><td>Command</td><td>Running commands</td><td><code>:</code></td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li>Normal mode is the default—use it most of the time.</li><li>Enter insert mode only when typing new text.</li><li>Return to normal mode as soon as you finish typing.</li><li>Visual mode makes selecting text visual and intuitive.</li><li>The bottom of the screen shows your current mode.</li><li>Practice switching between modes until it becomes automatic.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file and practice switching: Normal → Insert → Normal → Insert.</li><li>Enter visual mode, select some text, then press Escape.</li><li>Enter command mode (<code>:</code>) and type <code>:help modes</code>, then read about modes.</li><li>Practice all four ways to enter insert mode on the same line.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./08-opening-saving-quitting.html"><strong>Chapter 8 — Opening, Saving and Quitting</strong></a></p><p>Master the essential file operations that you&#39;ll use every day.</p>`,106)])])}const u=t(n,[["render",s]]);export{m as __pageData,u as default};
